<script>
const add=document.getElementById('addCard');document.getElementById('showAdd').onclick=()=>add.classList.add('open');document.getElementById('hideAdd').onclick=()=>add.classList.remove('open');
document.querySelectorAll('.cleanup-button').forEach(button=>button.onclick=async()=>{const section=button.closest('.section-body');const account=section.querySelector('.cleanup-account').value;const period=section.querySelector('.cleanup-period').value;if(!account)return alert('Выберите технический аккаунт.');if(!confirm('Удалить выбранные сообщения?'))return;const data=new FormData();data.append('chat',button.dataset.chat);data.append('account',account);data.append('period',period);button.disabled=true;try{const r=await fetch('{{ route('users.messages.delete') }}',{method:'POST',headers:{'Accept':'application/json','X-CSRF-TOKEN':'{{ csrf_token() }}'},body:data});const j=await r.json();alert(j.message||'Готово');}catch(e){alert('Ошибка удаления сообщений.')}finally{button.disabled=false;}});
</script>
